import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/Home.css';

// --- Icons (Inline SVGs for performance & no-deps) ---
const Icons = {
  Search: () => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>,
  MapPin: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>,
  Briefcase: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>,
  Upload: () => <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>,
  Chart: () => <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>,
  Plus: () => <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>,
  ArrowLeft: () => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>,
  Check: () => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
};

function Home() {
  const [activeTab, setActiveTab] = useState('home');
  const [jobs, setJobs] = useState([]);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/jobs');
      if (response.data.success) {
        setJobs(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching jobs:', error);
    }
  };

  const goHome = () => {
    setActiveTab('home');
    setMessage({ type: '', text: '' });
  };

  return (
    <div className="home-container">
      {activeTab === 'home' && (
        <>
          {/* Hero Section */}
          <section className="hero-section">
            <h2>Find Your Dream Job Today</h2>
            <p>Connect with top employers and find opportunities that match your skills perfectly with AI-powered matching.</p>

            <div className="hero-search">
              <input type="text" className="search-input" placeholder="Skills, Designation, Companies" />
              <input type="text" className="search-input" placeholder="Location" />
              <button className="search-btn">Search</button>
            </div>
          </section>

          {/* Action Grid */}
          <section className="action-grid">
            <div className="action-card" onClick={() => setActiveTab('post-job')}>
              <h3><Icons.Plus /> Post a New Job</h3>
              <p>Create a new job listing and let our AI engine find the perfect candidates for you.</p>
            </div>
            <div className="action-card" onClick={() => setActiveTab('upload-resume')}>
              <h3><Icons.Upload /> Upload Resume</h3>
              <p>Submit your resume to our database and get matched with multiple job openings instantly.</p>
            </div>
            <div className="action-card" onClick={() => setActiveTab('dashboard')}>
              <h3><Icons.Chart /> Ranking Dashboard</h3>
              <p>View detailed insights, candidate rankings, and skill match scores for your posted jobs.</p>
            </div>
          </section>

          {/* Job Feed */}
          <section className="jobs-section">
            <h3 className="section-title">Latest Opportunities</h3>
            <div className="jobs-grid">
              {jobs.length > 0 ? (
                jobs.map(job => (
                  <div key={job._id} className="job-card">
                    <div className="job-header">
                      <h4 className="job-title">{job.title}</h4>
                      <div className="company-name">{job.company || 'Top Tech Company'}</div>
                    </div>
                    <div className="job-tags">
                      {job.location && <span className="tag"><Icons.MapPin /> {job.location}</span>}
                      {job.type && <span className="tag"><Icons.Briefcase /> {job.type || 'Full-time'}</span>}
                    </div>
                    <p className="job-description">{job.description}</p>
                    <button className="apply-btn" onClick={() => setActiveTab('upload-resume')}>Apply Now</button>
                  </div>
                ))
              ) : (
                <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '40px', color: 'var(--text-secondary)' }}>
                  <p>No active job openings found right now.</p>
                  <button className="primary-btn" onClick={() => setActiveTab('post-job')} style={{ maxWidth: '200px', margin: '20px auto' }}>Post First Job</button>
                </div>
              )}
            </div>
          </section>
        </>
      )}

      {/* Forms & Dashboard Views */}
      {activeTab !== 'home' && (
        <div style={{ maxWidth: '900px', margin: '0 auto' }}>
          <button onClick={goHome} style={{ 
            marginBottom: '24px', 
            background: 'none', 
            color: 'var(--text-secondary)', 
            fontSize: '1rem', 
            display: 'flex', 
            alignItems: 'center', 
            gap: '8px',
            fontWeight: 600,
            padding: 0
          }}>
            <Icons.ArrowLeft /> Back to Home
          </button>

          {activeTab === 'post-job' && (
            <div className="form-container">
              <h2 style={{marginTop: 0, marginBottom: '24px'}}>Post a New Job</h2>
              <JobPostForm onJobCreated={() => { fetchJobs(); goHome(); }} setMessage={setMessage} />  
            </div>
          )}

          {activeTab === 'upload-resume' && (
            <div className="form-container">
              <h2 style={{marginTop: 0, marginBottom: '24px'}}>Upload Your Resume</h2>
              <ResumeUploadForm jobs={jobs} setMessage={setMessage} />
            </div>
          )}

          {activeTab === 'dashboard' && (
             <div className="form-container" style={{maxWidth: '100%'}}>
               <h2 style={{marginTop: 0, marginBottom: '24px'}}>Candidate Ranking Dashboard</h2>
               <Dashboard jobs={jobs} />
             </div>
          )}
        </div>
      )}

      {message.text && (
        <div className={`message ${message.type}`} style={{ 
          position: 'fixed', 
          bottom: '32px', 
          right: '32px', 
          zIndex: 1100, 
          boxShadow: '0 8px 16px rgba(0,0,0,0.15)',
          minWidth: '300px'
        }}>
          {message.text}
        </div>
      )}
    </div>
  );
}

function JobPostForm({ onJobCreated, setMessage }) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    requiredSkills: '',
    company: '',
    location: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const skills = formData.requiredSkills.split(',').map(s => s.trim()).filter(s => s);
      const response = await axios.post('http://localhost:5000/api/jobs', {
        ...formData,
        requiredSkills: skills
      });

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Job posted successfully!' });
        setFormData({ title: '', description: '', requiredSkills: '', company: '', location: '' });    
        onJobCreated();
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error posting job. Please try again.' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Job Title</label>
        <input
          type="text"
          value={formData.title}
          onChange={(e) => setFormData({...formData, title: e.target.value})}
          required
          placeholder="e.g. Senior Software Engineer"
        />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div className="form-group">
          <label>Company Name</label>
          <input
            type="text"
            value={formData.company}
            onChange={(e) => setFormData({...formData, company: e.target.value})}
            placeholder="e.g. TechCorp Inc."
          />
        </div>
        <div className="form-group">
          <label>Location</label>
          <input
            type="text"
            value={formData.location}
            onChange={(e) => setFormData({...formData, location: e.target.value})}
            placeholder="e.g. Remote, New York"
          />
        </div>
      </div>
      <div className="form-group">
        <label>Job Description</label>
        <textarea
          value={formData.description}
          onChange={(e) => setFormData({...formData, description: e.target.value})}
          required
          rows="6"
          placeholder="Describe the role, responsibilities, and perks..."
        />
      </div>
      <div className="form-group">
        <label>Required Skills (comma-separated)</label>
        <input
          type="text"
          value={formData.requiredSkills}
          onChange={(e) => setFormData({...formData, requiredSkills: e.target.value})}
          placeholder="e.g. React, Node.js, Python, AWS"
        />
      </div>
      <button type="submit" className="primary-btn">Create Job Listing</button>
    </form>
  );
}

function ResumeUploadForm({ jobs, setMessage }) {
  const [formData, setFormData] = useState({
    candidateName: '',
    email: '',
    phone: '',
    jobId: ''
  });
  const [file, setFile] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a resume file (PDF or DOCX)' });
      return;
    }

    const uploadData = new FormData();
    uploadData.append('resume', file);
    Object.keys(formData).forEach(key => uploadData.append(key, formData[key]));

    try {
      const response = await axios.post('http://localhost:5000/api/resumes/upload', uploadData);       
      if (response.data.success) {
        setMessage({ type: 'success', text: 'Application submitted successfully!' });
        setFormData({ candidateName: '', email: '', phone: '', jobId: '' });
        setFile(null);
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error uploading resume. Check file format.' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Select Job Position</label>
        <select
          value={formData.jobId}
          onChange={(e) => setFormData({...formData, jobId: e.target.value})}
          required
        >
          <option value="">-- Choose a position --</option>
          {jobs.map(job => (
            <option key={job._id} value={job._id}>
              {job.title} - {job.company || 'Company'}
            </option>
          ))}
        </select>
      </div>
      <div className="form-group">
        <label>Full Name</label>
        <input
          type="text"
          value={formData.candidateName}
          onChange={(e) => setFormData({...formData, candidateName: e.target.value})}
          required
          placeholder="Your full name"
        />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div className="form-group">
          <label>Email Address</label>
          <input
            type="email"
            value={formData.email}
            onChange={(e) => setFormData({...formData, email: e.target.value})}
            required
            placeholder="you@example.com"
          />
        </div>
        <div className="form-group">
          <label>Phone Number</label>
          <input
            type="tel"
            value={formData.phone}
            onChange={(e) => setFormData({...formData, phone: e.target.value})}
            placeholder="+1 (555) 000-0000"
          />
        </div>
      </div>
      <div className="form-group">
        <label>Upload Resume (PDF/DOCX)</label>
        <div style={{ 
          border: '2px dashed var(--border-color)', 
          padding: '24px', 
          borderRadius: '8px', 
          textAlign: 'center',
          background: 'var(--bg-color)'
        }}>
          <input
            type="file"
            accept=".pdf,.docx"
            onChange={(e) => setFile(e.target.files[0])}
            required
            style={{ border: 'none', background: 'transparent', padding: 0 }}
          />
          <p style={{marginTop: '8px', fontSize: '0.85rem', color: 'var(--text-tertiary)'}}>
            Maximum file size: 5MB
          </p>
        </div>
      </div>
      <button type="submit" className="primary-btn">Submit Application</button>
    </form>
  );
}

function Dashboard({ jobs }) {
  const [selectedJobId, setSelectedJobId] = useState('');
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const generateRankings = async () => {
    if (!selectedJobId) return;
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`http://localhost:5000/api/rankings/generate/${selectedJobId}`);
      if (response.data.success) {
        await fetchRankings();
      } else {
        setError(response.data.message || 'Failed to generate rankings');
      }
    } catch (error) {
      const errorMsg = error.response?.data?.message || error.message || 'Failed to generate rankings';
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const fetchRankings = async () => {
    if (!selectedJobId) return;
    try {
      const response = await axios.get(`http://localhost:5000/api/rankings/job/${selectedJobId}`);     
      if (response.data.success) {
        setRankings(response.data.data);
        setError('');
      }
    } catch (error) {
      setError('Failed to fetch rankings');
    }
  };

  useEffect(() => {
    if (selectedJobId) {
      fetchRankings();
    } else {
      setRankings([]);
      setError('');
    }
  }, [selectedJobId]);

  return (
    <div className="dashboard">
      <div className="form-group">
        <label>Select Job to Evaluate</label>
        <div style={{ display: 'flex', gap: '12px' }}>
          <select 
            value={selectedJobId} 
            onChange={(e) => setSelectedJobId(e.target.value)}
            style={{ flex: 1 }}
          >
            <option value="">-- Choose a job position --</option>
            {jobs.map(job => (
              <option key={job._id} value={job._id}>{job.title}</option>
            ))}
          </select>
          <button 
            onClick={generateRankings} 
            disabled={!selectedJobId || loading}
            className="primary-btn"
            style={{ width: 'auto', padding: '14px 24px', whiteSpace: 'nowrap' }}
          >
            {loading ? 'Analyzing...' : 'Analyze Candidates'}
          </button>
        </div>
      </div>

      {error && (
        <div className="message error">
           {error}
        </div>
      )}

      {loading && (
        <div style={{textAlign: 'center', padding: '48px', color: 'var(--text-secondary)'}}>
          <div className="spinner" style={{fontSize: '2rem', marginBottom: '16px'}}></div>
          <p>Analyzing resumes against job requirements...</p>
        </div>
      )}

      {!loading && rankings.length === 0 && selectedJobId && !error && (
        <div style={{
          textAlign: 'center', 
          padding: '48px', 
          color: 'var(--text-tertiary)', 
          border: '2px dashed var(--border-color)', 
          borderRadius: '12px',
          background: 'var(--bg-color)'
        }}>
          <h3>No rankings generated yet</h3>
          <p>Click "Analyze Candidates" to run the AI matching algorithm.</p>
        </div>
      )}

      {rankings.length > 0 && (
        <div className="rankings-list" style={{ marginTop: '32px' }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            marginBottom: '16px',
            borderBottom: '1px solid var(--border-color)',
            paddingBottom: '16px'
          }}>
            <h3 style={{margin: 0}}>Top Candidates ({rankings.length})</h3>
            <span style={{fontSize: '0.9rem', color: 'var(--text-secondary)'}}>Sorted by Match Score</span>
          </div>

          {rankings.map((ranking, index) => {
             const score = ranking.matchPercentage || 0;
             const matchClass = score >= 75 ? 'high-match' : (score >= 50 ? 'med-match' : 'low-match');

             return (
              <div key={ranking._id} className="ranking-card">
                <div className={`rank-badge ${matchClass}`}>
                  {score.toFixed(0)}%
                </div>

                <div className="candidate-info" style={{ flex: 1 }}>
                  <h4>{ranking.resumeId?.candidateName || 'Unknown Candidate'}</h4>
                  <p>{ranking.resumeId?.email}</p>
                  <p style={{fontSize: '0.85rem', marginTop: '4px', opacity: 0.8}}>
                    {ranking.resumeId?.phone}
                  </p>
                </div>

                <div className="skills-section">
                  <div className="matched-label">Matched Skills</div>
                  <div className="matched-skills">
                    {ranking.matchedSkills?.length > 0 ? (
                      ranking.matchedSkills.slice(0, 4).join(', ') + 
                      (ranking.matchedSkills.length > 4 ? ` +${ranking.matchedSkills.length - 4}` : '')
                    ) : (
                      <span style={{color: 'var(--text-tertiary)'}}>No specific matches</span>
                    )}
                  </div>
                </div>

                <div style={{ textAlign: 'right' }}>
                   <div style={{ fontSize: '2rem', color: '#e3e8ee', fontWeight: 700 }}>#{index + 1}</div>
                </div>
              </div>
             );
          })}
        </div>
      )}
    </div>
  );
}

export default Home;
